import React from 'react';
import { BrowserRouter as Router, Switch, Route } from 'react-router-dom';
import Header from './components/Header';
import Footer from './components/Footer';
import HomePage from './pages/homePage'; // Assurez-vous du bon nom ici, peut-être que le fichier s'appelle HomePage.js

import QuiJeSuis from './pages/Qui_Je_Suis'; // Assurez-vous que le chemin est correct
import MesServices from './pages/MesServices'; // Assurez-vous que le chemin est correct
import MesCompetences from './pages/MesCompetences'; // Assurez-vous que le chemin est correct
import MesProjets from './pages/MesProjets'; // Assurez-vous que le chemin est correct
import Contacts from './pages/Contacts'; // Assurez-vous que le chemin est correct

const App = () => {
  return (
    <Router>
      <Header />
      <Routes>
        <Route path="/" element={<HomePage />} />
        <Route path="/qui_je_suis" element={<QuiJeSuis />} />
        <Route path="/services" element={<MesServices />} />
        <Route path="/competences" element={<MesCompetences />} />
        <Route path="/projets" element={<MesProjets />} />
        <Route path="/contacts" element={<Contacts />} />
      </Routes>
      <Footer />
    </Router>
  );
};

export default App;
